using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF 9 renamed the discriminator property from "Discriminator" to "$type".
            // Keep the old name so existing documents and direct SQL queries still work.
            b.HasDiscriminator<string>("Discriminator");

            // EF 9 strips the discriminator from the JSON id (was "Product|123", now "123").
            // Restore the old composite format so existing documents remain addressable.
            b.HasDiscriminatorInJsonId();

            // EF 9 maps the key property directly to JSON id and drops the shadow __id.
            // This would remove the separate "Id" property from the JSON document.
            // Restore the shadow id so existing documents keep their schema.
            b.HasShadowId();

            // HasIndex was silently ignored before; EF 9 now throws.
            // Cosmos indexes all properties by default — manage custom policies via the Azure Portal.
            // b.HasIndex(p => p.Sku);  ← removed
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

