        // are unaffected, but any EF FromSqlRaw with scalar projections must add VALUE.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF 9 Cosmos no longer supports synchronous I/O — use async APIs.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

